#!/usr/bin/env python3\"\"\"\nOptimize Images Script for Fah Siam Website Manager\n\nThis script compresses and converts product images to WebP format for better web performance.\nIt supports batch processing and provides detailed compression statistics.\n\nUsage:\n    python optimize_images.py <repo_path> <image_files...>\n\nExample:\n    python optimize_images.py /home/ubuntu/web-fahsiam /path/to/image1.jpg /path/to/image2.png\n\"\"\"\n\nimport sys\nimport os\nfrom pathlib import Path\nfrom typing import List, Dict, Tuple\nimport subprocess\nimport json\n\ntry:\n    from PIL import Image\nexcept ImportError:\n    print(\"❌ Pillow library not found. Installing...\")\n    subprocess.run([sys.executable, '-m', 'pip', 'install', 'pillow'], check=True)\n    from PIL import Image\n\nclass ImageOptimizer:\n    \"\"\"Optimizes images for web performance.\"\"\"\n    \n    SUPPORTED_FORMATS = {'.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp'}\n    OUTPUT_FORMAT = 'webp'\n    OUTPUT_QUALITY = 85\n    MAX_WIDTH = 800\n    MAX_HEIGHT = 800\n    \n    def __init__(self, repo_path: str):\n        self.repo_path = Path(repo_path)\n        self.output_dir = self.repo_path / 'public' / 'image' / 'Fertilizer'\n        \n        # Create output directory if it doesn't exist\n        self.output_dir.mkdir(parents=True, exist_ok=True)\n    \n    def optimize_images(self, image_paths: List[str]) -> Tuple[bool, str, List[Dict]]:\n        \"\"\"\n        Optimize multiple images.\n        \n        Returns:\n            (success, summary_message, results_list)\n        \"\"\"\n        results = []\n        total_original_size = 0\n        total_optimized_size = 0\n        \n        for image_path in image_paths:\n            result = self.optimize_single_image(image_path)\n            results.append(result)\n            \n            if result['success']:\n                total_original_size += result['original_size']\n                total_optimized_size += result['optimized_size']\n        \n        # Generate summary\n        successful = sum(1 for r in results if r['success'])\n        failed = len(results) - successful\n        \n        summary = f\"✅ Image optimization complete!\\n\"\n        summary += f\"   Processed: {successful}/{len(results)} images\\n\"\n        \n        if failed > 0:\n            summary += f\"   Failed: {failed} images\\n\"\n        \n        if total_original_size > 0:\n            compression_ratio = (1 - total_optimized_size / total_original_size) * 100\n            size_reduction = total_original_size - total_optimized_size\n            \n            summary += f\"   Total compression: {compression_ratio:.1f}%\\n\"\n            summary += f\"   Size reduction: {self._format_size(total_original_size)} → {self._format_size(total_optimized_size)}\\n\"\n            summary += f\"   Saved: {self._format_size(size_reduction)}\\n\"\n        \n        summary += \"\\n   Details:\\n\"\n        for i, result in enumerate(results, 1):\n            if result['success']:\n                summary += f\"   {i}. ✅ {Path(result['input_path']).name}\\n\"\n                summary += f\"      Output: {result['output_path']}\\n\"\n                summary += f\"      Size: {self._format_size(result['original_size'])} → {self._format_size(result['optimized_size'])} ({result['compression']:.1f}%)\\n\"\n            else:\n                summary += f\"   {i}. ❌ {Path(result['input_path']).name} - {result['error']}\\n\"\n        \n        return len(results) == successful, summary, results\n    \n    def optimize_single_image(self, image_path: str) -> Dict:\n        \"\"\"\n        Optimize a single image.\n        \n        Returns:\n            Dictionary with optimization results\n        \"\"\"\n        input_path = Path(image_path)\n        \n        # Validate file exists\n        if not input_path.exists():\n            return {\n                'success': False,\n                'input_path': image_path,\n                'error': 'File not found'\n            }\n        \n        # Validate file format\n        if input_path.suffix.lower() not in self.SUPPORTED_FORMATS:\n            return {\n                'success': False,\n                'input_path': image_path,\n                'error': f'Unsupported format: {input_path.suffix}'\n            }\n        \n        try:\n            # Get original file size\n            original_size = input_path.stat().st_size\n            \n            # Open and process image\n            img = Image.open(input_path)\n            \n            # Convert RGBA to RGB if necessary (WebP optimization)\n            if img.mode in ('RGBA', 'LA', 'P'):\n                rgb_img = Image.new('RGB', img.size, (255, 255, 255))\n                rgb_img.paste(img, mask=img.split()[-1] if img.mode == 'RGBA' else None)\n                img = rgb_img\n            \n            # Resize if necessary\n            img.thumbnail((self.MAX_WIDTH, self.MAX_HEIGHT), Image.Resampling.LANCZOS)\n            \n            # Generate output path\n            output_filename = input_path.stem + '.webp'\n            output_path = self.output_dir / output_filename\n            \n            # Save optimized image\n            img.save(output_path, self.OUTPUT_FORMAT, quality=self.OUTPUT_QUALITY, method=6)\n            \n            # Get optimized file size\n            optimized_size = output_path.stat().st_size\n            compression = (1 - optimized_size / original_size) * 100 if original_size > 0 else 0\n            \n            return {\n                'success': True,\n                'input_path': image_path,\n                'output_path': str(output_path),\n                'original_size': original_size,\n                'optimized_size': optimized_size,\n                'compression': compression\n            }\n        \n        except Exception as e:\n            return {\n                'success': False,\n                'input_path': image_path,\n                'error': str(e)\n            }\n    \n    @staticmethod\n    def _format_size(size_bytes: int) -> str:\n        \"\"\"Format bytes to human-readable size.\"\"\"\n        for unit in ['B', 'KB', 'MB', 'GB']:\n            if size_bytes < 1024:\n                return f\"{size_bytes:.1f}{unit}\"\n            size_bytes /= 1024\n        return f\"{size_bytes:.1f}TB\"\n\ndef main():\n    \"\"\"Main entry point.\"\"\"\n    if len(sys.argv) < 3:\n        print(\"❌ Usage: python optimize_images.py <repo_path> <image_files...>\")\n        print(\"\\nExample:\")\n        print(\"  python optimize_images.py /home/ubuntu/web-fahsiam /path/to/image1.jpg /path/to/image2.png\")\n        sys.exit(1)\n    \n    repo_path = sys.argv[1]\n    image_files = sys.argv[2:]\n    \n    try:\n        optimizer = ImageOptimizer(repo_path)\n        success, summary, results = optimizer.optimize_images(image_files)\n        print(summary)\n        \n        # Output JSON results for programmatic use\n        print(\"\\n\" + json.dumps({\n            'success': success,\n            'results': results\n        }, indent=2, ensure_ascii=False))\n        \n        sys.exit(0 if success else 1)\n    \n    except Exception as e:\n        print(f\"❌ Error: {str(e)}\")\n        sys.exit(1)\n\nif __name__ == '__main__':\n    main()\n"
